import json
from openai import OpenAI

client = OpenAI()

# Tool definitions
tools = [
    {
        "type": "function",
        "function": {
            "name": "search_knowledge_base",
            "description": "Search the product knowledge base for relevant articles",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {"type": "string", "description": "The search query"},
                },
                "required": ["query"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "get_order_status",
            "description": "Get the status of a customer order",
            "parameters": {
                "type": "object",
                "properties": {
                    "order_id": {"type": "string"},
                },
                "required": ["order_id"],
            },
        },
    },
]

def execute_tool(name: str, args: dict) -> str:
    if name == "search_knowledge_base":
        return json.dumps({"results": [{"title": "Return Policy", "content": "30-day returns accepted."}]})
    elif name == "get_order_status":
        return json.dumps({"order_id": args["order_id"], "status": "shipped", "eta": "2026-07-03"})
    return json.dumps({"error": "unknown tool"})

class ToolEnabledAgent:
    def __init__(self, system_prompt: str):
        self.messages = [{"role": "system", "content": system_prompt}]

    def chat(self, user_input: str) -> str:
        self.messages.append({"role": "user", "content": user_input})

        # Agentic loop: keep going until the model produces a text reply
        while True:
            response = client.chat.completions.create(
                model="gpt-4o",
                messages=self.messages,
                tools=tools,
                tool_choice="auto",
            )
            msg = response.choices[0].message

            if msg.tool_calls:
                # Execute each tool call
                self.messages.append(msg)   # assistant message with tool_calls
                for tc in msg.tool_calls:
                    result = execute_tool(tc.function.name, json.loads(tc.function.arguments))
                    self.messages.append({
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": result,
                    })
                # Loop: model will now synthesise a reply using the tool results
            else:
                # Text reply — done for this turn
                self.messages.append({"role": "assistant", "content": msg.content})
                return msg.content

# ── Input and output guardrails ──────────────────────────────────────────────
import re

BLOCKED_PATTERNS = [
    r"ignore (previous|prior|all) instructions",
    r"you are now",
    r"jailbreak",
]

def check_input(user_input: str) -> str | None:
    """Return an error message if the input violates policy, else None."""
    lower = user_input.lower()
    for pattern in BLOCKED_PATTERNS:
        if re.search(pattern, lower):
            return "I cannot process that request."
    if len(user_input) > 4096:
        return "Your message is too long. Please keep it under 4,096 characters."
    return None

def check_output(response: str, topic: str) -> str:
    """Post-process the model's response."""
    # Redact common PII patterns from the response
    response = re.sub(r"\b\d{3}-\d{2}-\d{4}\b", "[SSN REDACTED]", response)
    response = re.sub(r"\b4[0-9]{12}(?:[0-9]{3})?\b", "[CARD REDACTED]", response)
    return response

class GuardedAgent:
    def chat(self, user_input: str) -> str:
        error = check_input(user_input)
        if error:
            return error
        # ... call the model ...
        reply = "placeholder"
        return check_output(reply, topic="support")
